export default defineNitroConfig({
  experimental: {
    tasks: true
  }
})

export default defineNuxtConfig({
  nitro: {
    experimental: {
      tasks: true
    }
  }
})

export default defineTask({
  meta: {
    name: "db:migrate",
    description: "运行数据库迁移",
  },
  run({ payload, context }) {
    console.log("正在运行数据库迁移任务...");
    return { result: "成功" };
  },
});

export default defineNitroConfig({
  scheduledTasks: {
    // 每分钟运行一次 `cms:update` 任务
    '* * * * *': ['cms:update']
  }
})

export default defineNuxtConfig({
  nitro: {
    scheduledTasks: {
      // 每分钟运行一次 `cms:update` 任务
      '* * * * *': ['cms:update']
    }
  }
})

export default eventHandler(async (event) => {
  // 重要：身份验证用户和验证负载！
  const payload = { ...getQuery(event) };
  const { result } = await runTask("db:migrate", { payload });

  return { result };
});

// [GET] /_nitro/tasks
{
  "tasks": {
    "db:migrate": {
      "description": "运行数据库迁移"
    },
    "cms:update": {
      "description": "更新 CMS 内容"
    }
  },
  "scheduledTasks": [
    {
      "cron": "* * * * *",
      "tasks": [
        "cms:update"
      ]
    }
  ]
}

export default defineTask({
  meta: {
    name: "echo:payload",
    description: "返回提供的负载",
  },
  run({ payload, context }) {
    console.log("正在运行回声任务...");
    return { result: payload };
  },
});
